1	import { BasicBuilder } from './BasicBuilder'
2	import { Writer } from './Writer'
3	
4	export class DocComment implements BasicBuilder {
5	  readonly lines: string[] = []
6	
7	  constructor(startingText?: string) {
8	    if (startingText) {
9	      this.addText(startingText)
10	    }
11	  }
12	
13	  addText(text: string): this {
14	    this.lines.push(...text.split('\n'))
15	    return this
16	  }
17	
18	  write(writer: Writer) {
19	    writer.writeLine('/**')
20	    for (const line of this.lines) {
21	      writer.writeLine(` * ${line}`)
22	    }
23	    writer.writeLine(' */')
24	    return writer
25	  }
26	}
27	
28	function docComment(strings: TemplateStringsArray, ...args: string[]): DocComment
29	function docComment(startingText?: string): DocComment
30	function docComment(firstParameter: string | TemplateStringsArray | undefined, ...args: string[]): DocComment {
31	  if (typeof firstParameter === 'string' || typeof firstParameter === 'undefined') {
32	    return new DocComment(firstParameter)
33	  }
34	  return docCommentTag(firstParameter, args)
35	}
36	
37	function docCommentTag(strings: TemplateStringsArray, args: string[]) {
38	  const docComment = new DocComment()
39	  const fullText = strings
40	    .flatMap((str, i) => {
41	      if (i < args.length) {
42	        return [str, args[i]]
43	      }
44	      return [str]
45	    })
46	    .join('')
47	  const lines = trimEmptyLines(fullText.split('\n'))
48	  if (lines.length === 0) {
49	    return docComment
50	  }
51	  const indent = getIndent(lines[0])
52	  for (const line of lines) {
53	    docComment.addText(line.slice(indent))
54	  }
55	  return docComment
56	}
57	
58	function trimEmptyLines(lines: string[]): string[] {
59	  const firstLine = findFirstNonEmptyLine(lines)
60	  const lastLine = findLastNonEmptyLine(lines)
61	  if (firstLine === -1 || lastLine === -1) {
62	    // all lines are empty
63	    return []
64	  }
65	  return lines.slice(firstLine, lastLine + 1)
66	}
67	
68	function findFirstNonEmptyLine(lines: string[]) {
69	  return lines.findIndex((line) => !isEmptyLine(line))
70	}
71	
72	function findLastNonEmptyLine(lines: string[]) {
73	  let i = lines.length - 1
74	  while (i > 0 && isEmptyLine(lines[i])) {
75	    i--
76	  }
77	  return i
78	}
79	
80	function isEmptyLine(line: string) {
81	  return line.trim().length === 0
82	}
83	
84	function getIndent(line: string): number {
85	  let indent = 0
86	  while (line[indent] === ' ') {
87	    indent++
88	  }
89	  return indent
90	}
91	
92	export { docComment }
