88	/**
89	 * Examples:
90	 * T[], T => T | T[]
91	 * T, U => XOR<T,U>
92	 * T[], T, U => XOR<T, U> | T[]
93	 * T[], U => T[] | U
94	 * T, U, null => XOR<T,U> | null
95	 * T, U, V, W, null => XOR<T, XOR<U, XOR<V, W>>> | null
96	 *
97	 * 1. Separate XOR and non XOR items (objects and non-objects)
98	 * 2. Generate them out and `|` them
99	 */
100	function buildAllFieldTypes(
101	  inputTypes: readonly DMMF.InputTypeRef[],
102	  context: GenerateContext,
103	  source?: string,
104	): ts.TypeBuilder {
105	  const inputObjectTypes = inputTypes.filter((t) => t.location === 'inputObjectTypes' && !t.isList)
106	
107	  const otherTypes = inputTypes.filter((t) => t.location !== 'inputObjectTypes' || t.isList)
108	
109	  const tsInputObjectTypes = inputObjectTypes.map((type) => buildSingleFieldType(type, context.genericArgsInfo, source))
110	
111	  const tsOtherTypes = otherTypes.map((type) => buildSingleFieldType(type, context.genericArgsInfo, source))
112	
113	  if (tsOtherTypes.length === 0) {
114	    return xorTypes(tsInputObjectTypes)
115	  }
116	
117	  if (tsInputObjectTypes.length === 0) {
118	    return ts.unionType(tsOtherTypes)
119	  }
