import type { Field } from '@prisma/dmmf'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  BigInt: 'bigint',
  Decimal: 'string',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
}

/**
 * Maps a Prisma DMMF field type to a TypeScript type string.
 * Scalar types are mapped to their TS equivalents; enum types use the enum name directly.
 * Returns `undefined` for relation (object) and unsupported fields.
 */
export function mapFieldToTsType(field: Field): string | undefined {
  if (field.kind === 'object' || field.kind === 'unsupported') {
    return undefined
  }

  let tsType: string

  if (field.kind === 'enum') {
    tsType = field.type
  } else {
    tsType = SCALAR_TYPE_MAP[field.type] ?? 'unknown'
  }

  if (field.isList) {
    tsType = `${tsType}[]`
  }

  if (!field.isRequired && !field.isList) {
    tsType = `${tsType} | null`
  }

  return tsType
}

/**
 * Returns whether a field should be omitted from create input
 * because it has an auto-generated value.
 */
export function isAutoGeneratedField(field: Field): boolean {
  if (field.isGenerated) return true
  if (field.isUpdatedAt) return true
  if (field.isReadOnly) return true

  if (field.hasDefaultValue) {
    if (field.isId) return true

    const def = field.default
    if (typeof def === 'object' && def !== null && !Array.isArray(def) && 'name' in def) {
      const name = (def as { name: string }).name
      if (name === 'autoincrement' || name === 'uuid' || name === 'cuid' || name === 'now' || name === 'auto') {
        return true
      }
    }
  }

  return false
}

