import fs from 'node:fs'
import path from 'node:path'

import type { Datamodel, DatamodelEnum, Field, Model } from '@prisma/dmmf'

import { isAutoGeneratedField, mapFieldToTsType } from './type-mapper'

export interface GenerateRestClientOptions {
  datamodel: Datamodel
  outputDir: string
}

/**
 * Generates a fully typed REST API client from the DMMF datamodel.
 * Writes a single `rest-client.ts` file containing interfaces and CRUD client classes.
 */
export function generateRestClient({ datamodel, outputDir }: GenerateRestClientOptions): void {
  const lines: string[] = []

  lines.push('// ------------------------------------------------')
  lines.push('// This file was generated by @prisma/rest-api-generator')
  lines.push('// Do not edit manually.')
  lines.push('// ------------------------------------------------')
  lines.push('')

  for (const enumType of datamodel.enums) {
    lines.push(...generateEnum(enumType))
    lines.push('')
  }

  for (const model of datamodel.models) {
    lines.push(...generateModelInterface(model))
    lines.push('')
    lines.push(...generateCreateInput(model))
    lines.push('')
    lines.push(...generateUpdateInput(model))
    lines.push('')
    lines.push(...generateModelClient(model))
    lines.push('')
  }

  lines.push(...generateMainClient(datamodel.models))

  fs.mkdirSync(outputDir, { recursive: true })
  fs.writeFileSync(path.join(outputDir, 'rest-client.ts'), lines.join('\n'))
}

function generateEnum(enumType: DatamodelEnum): string[] {
  const lines: string[] = []

  if (enumType.documentation) {
    lines.push(`/** ${enumType.documentation} */`)
  }

  lines.push(`export enum ${enumType.name} {`)
  for (const value of enumType.values) {
    lines.push(`  ${value.name} = '${value.name}',`)
  }
  lines.push('}')

  return lines
}

function getScalarFields(model: Model): Field[] {
  return model.fields.filter((f) => f.kind !== 'object' && f.kind !== 'unsupported')
}

function getIdField(model: Model): Field | undefined {
  return model.fields.find((f) => f.isId)
}

function generateModelInterface(model: Model): string[] {
  const lines: string[] = []

  if (model.documentation) {
    lines.push(`/** ${model.documentation} */`)
  }

  lines.push(`export interface ${model.name} {`)

  for (const field of getScalarFields(model)) {
    const tsType = mapFieldToTsType(field)
    if (tsType === undefined) continue

    if (field.documentation) {
      lines.push(`  /** ${field.documentation} */`)
    }
    lines.push(`  ${field.name}: ${tsType}`)
  }

  lines.push('}')

  return lines
}

function generateCreateInput(model: Model): string[] {
  const lines: string[] = []
  lines.push(`export interface ${model.name}CreateInput {`)

  for (const field of getScalarFields(model)) {
    const tsType = mapFieldToTsType(field)
    if (tsType === undefined) continue
    if (field.kind === 'object') continue

    const autoGenerated = isAutoGeneratedField(field)
    const optional = autoGenerated || !field.isRequired || field.hasDefaultValue

    if (field.documentation) {
      lines.push(`  /** ${field.documentation} */`)
    }
    lines.push(`  ${field.name}${optional ? '?' : ''}: ${tsType}`)
  }

  lines.push('}')

  return lines
}

function generateUpdateInput(model: Model): string[] {
  const lines: string[] = []
  lines.push(`export interface ${model.name}UpdateInput {`)

  for (const field of getScalarFields(model)) {
    const tsType = mapFieldToTsType(field)
    if (tsType === undefined) continue
    if (field.isId) continue

    if (field.documentation) {
      lines.push(`  /** ${field.documentation} */`)
    }
    lines.push(`  ${field.name}?: ${tsType}`)
  }

  lines.push('}')

  return lines
}

function getIdTsType(model: Model): string {
  const idField = getIdField(model)
  if (!idField) return 'string'

  const mapped = mapFieldToTsType(idField)
  if (!mapped) return 'string'

  // Strip `| null` from the id type since IDs are always required for lookups
  return mapped.replace(' | null', '')
}

function modelEndpoint(model: Model): string {
  return model.name.charAt(0).toLowerCase() + model.name.slice(1)
}

function generateModelClient(model: Model): string[] {
  const lines: string[] = []
  const name = model.name
  const endpoint = modelEndpoint(model)
  const idType = getIdTsType(model)

  lines.push(`export class ${name}Client {`)
  lines.push(`  #baseUrl: string`)
  lines.push('')
  lines.push(`  constructor(baseUrl: string) {`)
  lines.push(`    this.#baseUrl = baseUrl`)
  lines.push(`  }`)
  lines.push('')

  // findMany
  lines.push(`  /** Retrieve all ${name} records. */`)
  lines.push(`  async findMany(): Promise<${name}[]> {`)
  lines.push(`    const response = await fetch(\`\${this.#baseUrl}/${endpoint}\`)`)
  lines.push(`    if (!response.ok) {`)
  lines.push(`      throw new Error(\`GET /${endpoint} failed with status \${response.status}\`)`)
  lines.push(`    }`)
  lines.push(`    return response.json() as Promise<${name}[]>`)
  lines.push(`  }`)
  lines.push('')

  // findUnique
  lines.push(`  /** Retrieve a single ${name} by its ID. */`)
  lines.push(`  async findUnique(id: ${idType}): Promise<${name} | null> {`)
  lines.push(`    const response = await fetch(\`\${this.#baseUrl}/${endpoint}/\${id}\`)`)
  lines.push(`    if (response.status === 404) return null`)
  lines.push(`    if (!response.ok) {`)
  lines.push(`      throw new Error(\`GET /${endpoint}/\${id} failed with status \${response.status}\`)`)
  lines.push(`    }`)
  lines.push(`    return response.json() as Promise<${name}>`)
  lines.push(`  }`)
  lines.push('')

  // create
  lines.push(`  /** Create a new ${name} record. */`)
  lines.push(`  async create(data: ${name}CreateInput): Promise<${name}> {`)
  lines.push(`    const response = await fetch(\`\${this.#baseUrl}/${endpoint}\`, {`)
  lines.push(`      method: 'POST',`)
  lines.push(`      headers: { 'Content-Type': 'application/json' },`)
  lines.push(`      body: JSON.stringify(data),`)
  lines.push(`    })`)
  lines.push(`    if (!response.ok) {`)
  lines.push(`      throw new Error(\`POST /${endpoint} failed with status \${response.status}\`)`)
  lines.push(`    }`)
  lines.push(`    return response.json() as Promise<${name}>`)
  lines.push(`  }`)
  lines.push('')

  // update
  lines.push(`  /** Update an existing ${name} record by its ID. */`)
  lines.push(`  async update(id: ${idType}, data: ${name}UpdateInput): Promise<${name}> {`)
  lines.push(`    const response = await fetch(\`\${this.#baseUrl}/${endpoint}/\${id}\`, {`)
  lines.push(`      method: 'PATCH',`)
  lines.push(`      headers: { 'Content-Type': 'application/json' },`)
  lines.push(`      body: JSON.stringify(data),`)
  lines.push(`    })`)
  lines.push(`    if (!response.ok) {`)
  lines.push(`      throw new Error(\`PATCH /${endpoint}/\${id} failed with status \${response.status}\`)`)
  lines.push(`    }`)
  lines.push(`    return response.json() as Promise<${name}>`)
  lines.push(`  }`)
  lines.push('')

  // delete
  lines.push(`  /** Delete a ${name} record by its ID. */`)
  lines.push(`  async delete(id: ${idType}): Promise<${name}> {`)
  lines.push(`    const response = await fetch(\`\${this.#baseUrl}/${endpoint}/\${id}\`, {`)
  lines.push(`      method: 'DELETE',`)
  lines.push(`    })`)
  lines.push(`    if (!response.ok) {`)
  lines.push(`      throw new Error(\`DELETE /${endpoint}/\${id} failed with status \${response.status}\`)`)
  lines.push(`    }`)
  lines.push(`    return response.json() as Promise<${name}>`)
  lines.push(`  }`)

  lines.push('}')

  return lines
}

function generateMainClient(models: readonly Model[]): string[] {
  const lines: string[] = []

  lines.push('/** Auto-generated REST API client with typed methods for every Prisma model. */')
  lines.push('export class PrismaRestApiClient {')

  for (const model of models) {
    const endpoint = modelEndpoint(model)
    lines.push(`  readonly ${endpoint}: ${model.name}Client`)
  }

  lines.push('')
  lines.push('  constructor(baseUrl: string) {')

  for (const model of models) {
    const endpoint = modelEndpoint(model)
    lines.push(`    this.${endpoint} = new ${model.name}Client(baseUrl)`)
  }

  lines.push('  }')
  lines.push('}')
  lines.push('')

  return lines
}

