import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateRestClient } from './generate-rest-client'

/**
 * Prisma generator that produces a typed REST API client.
 * For each model in the schema, it generates TypeScript interfaces
 * and a client class with CRUD methods (findMany, findUnique, create, update, delete).
 */
export class PrismaRestApiGenerator implements Generator {
  readonly name = 'prisma-rest-api'

  getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      defaultOutput: './generated/rest-client',
      prettyName: 'Prisma REST API Client',
      requiresEngines: [],
    })
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const output = options.generator.output
    if (!output?.value) {
      throw new Error('No output directory specified for @prisma/rest-api-generator')
    }

    generateRestClient({
      datamodel: options.dmmf.datamodel,
      outputDir: output.value,
    })
  }
}

