describe('generateRestClient', () => {
  let outputDir: string

  beforeEach(() => {
    outputDir = fs.mkdtempSync(path.join(os.tmpdir(), 'prisma-rest-gen-'))
  })

  afterEach(() => {
    fs.rmSync(outputDir, { recursive: true, force: true })
  })

  test('generates a valid rest-client.ts file for a simple model', () => {
    const userModel = makeModel({
      name: 'User',
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
        makeField({ name: 'email', type: 'String', isUnique: true }),
        makeField({ name: 'name', type: 'String', isRequired: false }),
        makeField({ name: 'createdAt', type: 'DateTime', hasDefaultValue: true, default: { name: 'now', args: [] } }),
        makeField({ name: 'posts', kind: 'object', type: 'Post', isList: true, relationName: 'UserPosts' }),
      ],
    })

    const datamodel = makeDatamodel([userModel])

    generateRestClient({ datamodel, outputDir })

    const outputFile = path.join(outputDir, 'rest-client.ts')
    expect(fs.existsSync(outputFile)).toBe(true)

    const content = fs.readFileSync(outputFile, 'utf-8')

    // Model interface
    expect(content).toContain('export interface User {')
    expect(content).toContain('  id: number')
    expect(content).toContain('  email: string')
    expect(content).toContain('  name: string | null')
    expect(content).toContain('  createdAt: string')
    // Relation fields are excluded from the interface
    expect(content).not.toContain('posts:')

    // CreateInput - auto-generated fields are optional
    expect(content).toContain('export interface UserCreateInput {')
    expect(content).toContain('  id?: number')
    expect(content).toContain('  email: string')
    expect(content).toContain('  name?: string | null')
    expect(content).toContain('  createdAt?: string')

    // UpdateInput - all fields optional, id excluded
    expect(content).toContain('export interface UserUpdateInput {')
    expect(content).toMatch(/UserUpdateInput[\s\S]*?email\?: string/)
    expect(content).toMatch(/UserUpdateInput[\s\S]*?name\?: string \| null/)
    // id should not be in UpdateInput
    const updateSection = content.slice(content.indexOf('UserUpdateInput'), content.indexOf('}', content.indexOf('UserUpdateInput')) + 1)
    expect(updateSection).not.toContain('  id?')

    // Client class with CRUD methods
    expect(content).toContain('export class UserClient {')
    expect(content).toContain('async findMany(): Promise<User[]>')
    expect(content).toContain('async findUnique(id: number): Promise<User | null>')
    expect(content).toContain('async create(data: UserCreateInput): Promise<User>')
    expect(content).toContain('async update(id: number, data: UserUpdateInput): Promise<User>')
    expect(content).toContain('async delete(id: number): Promise<User>')

    // Main client class
    expect(content).toContain('export class PrismaRestApiClient {')
    expect(content).toContain('readonly user: UserClient')
  })

  test('generates clients for multiple models', () => {
    const userModel = makeModel({
      name: 'User',
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
        makeField({ name: 'email', type: 'String' }),
      ],
    })

    const postModel = makeModel({
      name: 'Post',
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
        makeField({ name: 'title', type: 'String' }),
        makeField({ name: 'published', type: 'Boolean' }),
        makeField({ name: 'authorId', type: 'Int' }),
      ],
    })

    const datamodel = makeDatamodel([userModel, postModel])

    generateRestClient({ datamodel, outputDir })

    const content = fs.readFileSync(path.join(outputDir, 'rest-client.ts'), 'utf-8')

    expect(content).toContain('export interface User {')
    expect(content).toContain('export interface Post {')
    expect(content).toContain('export class UserClient {')
    expect(content).toContain('export class PostClient {')
    expect(content).toContain('export class PrismaRestApiClient {')
    expect(content).toContain('readonly user: UserClient')
    expect(content).toContain('readonly post: PostClient')
  })

  test('generates enum types', () => {
    const model = makeModel({
      name: 'User',
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
        makeField({ name: 'role', kind: 'enum', type: 'Role' }),
      ],
    })

    const roleEnum: DMMF.DatamodelEnum = {
      name: 'Role',
      values: [
        { name: 'USER', dbName: null },
        { name: 'ADMIN', dbName: null },
      ],
    }

    const datamodel = makeDatamodel([model], [roleEnum])

    generateRestClient({ datamodel, outputDir })

    const content = fs.readFileSync(path.join(outputDir, 'rest-client.ts'), 'utf-8')

    expect(content).toContain('export enum Role {')
    expect(content).toContain("  USER = 'USER',")
    expect(content).toContain("  ADMIN = 'ADMIN',")
    expect(content).toContain('  role: Role')
  })

  test('handles string ID types', () => {
    const model = makeModel({
      name: 'Item',
      fields: [
        makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true, default: { name: 'uuid', args: [4] } }),
        makeField({ name: 'value', type: 'String' }),
      ],
    })

    const datamodel = makeDatamodel([model])

    generateRestClient({ datamodel, outputDir })

    const content = fs.readFileSync(path.join(outputDir, 'rest-client.ts'), 'utf-8')

    expect(content).toContain('async findUnique(id: string): Promise<Item | null>')
    expect(content).toContain('async update(id: string, data: ItemUpdateInput): Promise<Item>')
    expect(content).toContain('async delete(id: string): Promise<Item>')
  })

  test('generates the header comment', () => {
    const model = makeModel({
      name: 'Foo',
      fields: [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
      ],
    })

    generateRestClient({ datamodel: makeDatamodel([model]), outputDir })

    const content = fs.readFileSync(path.join(outputDir, 'rest-client.ts'), 'utf-8')
    expect(content).toContain('This file was generated by @prisma/rest-api-generator')
    expect(content).toContain('Do not edit manually.')
  })
})

