      },
      datasources: [],
      datamodel: '',
      version: 'test',
    } as unknown as GeneratorOptions

    await expect(generator.generate(options)).rejects.toThrow('No output directory specified')
  })

  test('generate writes output to the specified directory', async () => {
    const generator = new PrismaRestApiGenerator()
    const outputDir = fs.mkdtempSync(path.join(os.tmpdir(), 'prisma-rest-gen-test-'))

    try {
      const options = {
        generator: {
          name: 'test',
          output: { fromEnvVar: null, value: outputDir },
          provider: { fromEnvVar: null, value: '@prisma/rest-api-generator' },
          config: {},
          binaryTargets: [],
          previewFeatures: [],
          sourceFilePath: '/test/schema.prisma',
        },
        otherGenerators: [],
        schemaPath: '/test/schema.prisma',
        dmmf: {
          datamodel: {
            models: [
              makeModel({
                name: 'Todo',
                fields: [
                  makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
                  makeField({ name: 'title', type: 'String' }),
                  makeField({ name: 'done', type: 'Boolean' }),
                ],
              }),
            ],
            enums: [],
            types: [],
            indexes: [],
          },
          schema: {
            inputObjectTypes: {},
            outputObjectTypes: { model: [], prisma: [] },
            enumTypes: { prisma: [] },
            fieldRefTypes: {},
          },
          mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
        },
        datasources: [],
        datamodel: '',
        version: 'test',
      } as unknown as GeneratorOptions

      await generator.generate(options)

      const outputFile = path.join(outputDir, 'rest-client.ts')
      expect(fs.existsSync(outputFile)).toBe(true)

      const content = fs.readFileSync(outputFile, 'utf-8')
      expect(content).toContain('export interface Todo {')
      expect(content).toContain('export class TodoClient {')
      expect(content).toContain('export class PrismaRestApiClient {')
    } finally {
      fs.rmSync(outputDir, { recursive: true, force: true })
    }
  })
})

